var COURSE_TR_SQ = [{day: 1, title: `Selamlaşma ve İlk Sözler`, title_native: `Përshëndetje dhe fjalët e para`, focus: `Tiran’da bir kafeye, otele veya küçük dükkâna girerken kullanacağın en temel selamlaşmaları öğrenirsin. Amaç, ilk temas anında kibar ve rahat görünmek.`, vocab: [{sq: `përshëndetje`, tr: `merhaba`, ipa: `pır-shın-DET-ye`},{sq: `mirëdita`, tr: `iyi günler`, ipa: `mi-rı-Dİ-ta`},{sq: `mirëmëngjes`, tr: `günaydın`, ipa: `mi-rı-MIN-gyes`},{sq: `mirëmbrëma`, tr: `iyi akşamlar`, ipa: `mi-rım-BRI-ma`},{sq: `natën e mirë`, tr: `iyi geceler`, ipa: `NA-tın e Mİ-rı`},{sq: `po`, tr: `evet`, ipa: `po`},{sq: `jo`, tr: `hayır`, ipa: `yo`},{sq: `faleminderit`, tr: `teşekkür ederim`, ipa: `fa-le-min-DE-rit`},{sq: `ju lutem`, tr: `lütfen / rica ederim`, ipa: `yu LU-tem`},{sq: `mirupafshim`, tr: `hoşça kalın`, ipa: `mi-ru-PAF-shim`}], phrases: [{sq: `Përshëndetje!`, tr: `Merhaba!`, ipa: `pır-shın-DET-ye`},{sq: `Mirëdita, si jeni?`, tr: `İyi günler, nasılsınız?`, ipa: `mi-rı-Dİ-ta si YE-ni`},{sq: `Jam mirë, faleminderit.`, tr: `İyiyim, teşekkür ederim.`, ipa: `yam Mİ-rı fa-le-min-DE-rit`},{sq: `Po, ju lutem.`, tr: `Evet, lütfen.`, ipa: `po yu LU-tem`},{sq: `Jo, faleminderit.`, tr: `Hayır, teşekkür ederim.`, ipa: `yo fa-le-min-DE-rit`},{sq: `Mirupafshim!`, tr: `Hoşça kalın!`, ipa: `mi-ru-PAF-shim`}], grammar: `Arnavutçada “ju” kibar veya çoğul “siz” anlamına gelir. Yeni tanıştığın kişilerle, otel çalışanlarıyla ve restoran personeliyle “ju” kullanmak güvenli ve naziktir. “Si jeni?” kibar “Nasılsınız?” sorusudur.`, practice: [`Bir kafeye girerken Arnavutça “Merhaba” de.`,`“İyiyim, teşekkür ederim” cümlesini yüksek sesle üç kez söyle.`,`“Evet, lütfen” ve “Hayır, teşekkür ederim” ifadelerini karşılaştır.`,`Otel resepsiyonunda “İyi akşamlar” demeyi canlandır.`,`Bir dükkândan çıkarken “Hoşça kalın” kullan.`]},{day: 2, title: `Kendini Tanıtma`, title_native: `Prezantimi i vetes`, focus: `Priştine’de veya Tiran’da biriyle tanışırken adını, nereli olduğunu ve turist olduğunu söylemeyi öğrenirsin. Kısa ve doğal tanıtım cümleleri kurarsın.`, vocab: [{sq: `unë`, tr: `ben`, ipa: `U-nı`},{sq: `ti`, tr: `sen`, ipa: `ti`},{sq: `ju`, tr: `siz`, ipa: `yu`},{sq: `jam`, tr: `benim / -im`, ipa: `yam`},{sq: `quhem`, tr: `adım ...`, ipa: `ÇU-hem`},{sq: `emër`, tr: `isim`, ipa: `E-mır`},{sq: `nga`, tr: `-den / -dan`, ipa: `nga`},{sq: `Turqia`, tr: `Türkiye`, ipa: `TUR-çi-a`},{sq: `turist`, tr: `turist`, ipa: `tu-RİST`},{sq: `shumë mirë`, tr: `çok iyi`, ipa: `SHU-mı Mİ-rı`}], phrases: [{sq: `Unë quhem Ali.`, tr: `Benim adım Ali.`, ipa: `U-nı ÇU-hem A-li`},{sq: `Jam nga Turqia.`, tr: `Türkiye’denim.`, ipa: `yam nga TUR-çi-a`},{sq: `Jam turist.`, tr: `Turistim.`, ipa: `yam tu-RİST`},{sq: `Si quheni?`, tr: `Adınız nedir?`, ipa: `si ÇU-he-ni`},{sq: `Gëzohem që ju njoh.`, tr: `Tanıştığıma memnun oldum.`, ipa: `gı-ZO-hem çı yu nyoh`},{sq: `Edhe unë.`, tr: `Ben de.`, ipa: `E-de U-nı`}], grammar: `“Jam” kelimesi “ben ...-im” anlamı verir: “Jam turist” = “Turistim.” Arnavutçada çoğu zaman özne zamirini söylemeden de cümle kurulabilir, ama başlangıçta “unë jam” demek anlamı netleştirir.`, practice: [`Kendi adınla “Unë quhem ...” cümlesi kur.`,`“Jam nga Turqia” cümlesini ezberle.`,`Birine kibarca “Si quheni?” diye sor.`,`Tanışma sonunda “Gëzohem që ju njoh” de.`,`“Ben de” anlamındaki ifadeyi bir diyaloğa ekle.`]},{day: 3, title: `Sayılar ve Temel Bilgiler`, title_native: `Numrat dhe informacionet bazë`, focus: `Tiran Pazarı’nda fiyat sormak, masa numarası anlamak veya telefon numarası vermek için temel sayıları öğrenirsin.`, vocab: [{sq: `zero`, tr: `sıfır`, ipa: `ZE-ro`},{sq: `një`, tr: `bir`, ipa: `nyı`},{sq: `dy`, tr: `iki`, ipa: `dü`},{sq: `tre`, tr: `üç`, ipa: `tre`},{sq: `katër`, tr: `dört`, ipa: `KA-tır`},{sq: `pesë`, tr: `beş`, ipa: `PE-sı`},{sq: `gjashtë`, tr: `altı`, ipa: `GYAŞT`},{sq: `shtatë`, tr: `yedi`, ipa: `ŞTA-tı`},{sq: `tetë`, tr: `sekiz`, ipa: `TE-tı`},{sq: `dhjetë`, tr: `on`, ipa: `DHYE-tı`}], phrases: [{sq: `Një kafe, ju lutem.`, tr: `Bir kahve lütfen.`, ipa: `nyı KA-fe yu LU-tem`},{sq: `Dy bileta, ju lutem.`, tr: `İki bilet lütfen.`, ipa: `dü bi-LE-ta yu LU-tem`},{sq: `Sa kushton?`, tr: `Ne kadar?`, ipa: `sa KUŞ-ton`},{sq: `Kushton pesë euro.`, tr: `Beş avro tutuyor.`, ipa: `KUŞ-ton PE-sı EV-ro`},{sq: `Numri im është tre.`, tr: `Numaram üç.`, ipa: `NUM-ri im EŞ-tı tre`},{sq: `Edhe një, ju lutem.`, tr: `Bir tane daha lütfen.`, ipa: `E-de nyı yu LU-tem`}], grammar: `Arnavutçada sayıdan sonra isim genellikle çoğul biçimde gelebilir ama turistik pratikte “një kafe”, “dy bileta” gibi kalıpları ezberlemek yeterlidir. “Sa kushton?” tek bir şeyin fiyatını sormak için çok kullanışlıdır.`, practice: [`0’dan 10’a kadar sayıları sırayla oku.`,`“İki bilet lütfen” cümlesini kur.`,`Bir pazarda “Sa kushton?” diye sorduğunu hayal et.`,`“Bir tane daha lütfen” ifadesini kahve siparişinde kullan.`,`Kendi oda numaranı Arnavutça söylemeyi dene.`]},{day: 4, title: `Kibar İfadeler ve Özür Dileme`, title_native: `Shprehje të sjellshme dhe kërkim faljeje`, focus: `İşkodra sokaklarında yol sorarken, kalabalıkta geçerken veya yanlış anlama olduğunda kullanacağın kibar ifadeleri öğrenirsin.`, vocab: [{sq: `më falni`, tr: `affedersiniz`, ipa: `mı FAL-ni`},{sq: `falje`, tr: `özür`, ipa: `FAL-ye`},{sq: `s’ka problem`, tr: `sorun değil`, ipa: `ska prob-LEM`},{sq: `mirë`, tr: `iyi / tamam`, ipa: `Mİ-rı`},{sq: `keq`, tr: `kötü`, ipa: `keç`},{sq: `ngadalë`, tr: `yavaş`, ipa: `nga-DA-lı`},{sq: `përsëri`, tr: `tekrar`, ipa: `pır-Sı-ri`},{sq: `kuptoj`, tr: `anlıyorum`, ipa: `kup-TOY`},{sq: `nuk kuptoj`, tr: `anlamıyorum`, ipa: `nuk kup-TOY`},{sq: `ndihmë`, tr: `yardım`, ipa: `NDİH-mı`}], phrases: [{sq: `Më falni.`, tr: `Affedersiniz.`, ipa: `mı FAL-ni`},{sq: `Më falni, nuk kuptoj.`, tr: `Affedersiniz, anlamıyorum.`, ipa: `mı FAL-ni nuk kup-TOY`},{sq: `A mund ta përsërisni?`, tr: `Tekrar edebilir misiniz?`, ipa: `a mund ta pır-sı-RİS-ni`},{sq: `Flisni ngadalë, ju lutem.`, tr: `Lütfen yavaş konuşun.`, ipa: `FLİS-ni nga-DA-lı yu LU-tem`},{sq: `S’ka problem.`, tr: `Sorun değil.`, ipa: `ska prob-LEM`},{sq: `Kam nevojë për ndihmë.`, tr: `Yardıma ihtiyacım var.`, ipa: `kam ne-VO-yı pır NDİH-mı`}], grammar: `“Nuk” olumsuzluk kelimesidir ve fiilden önce gelir: “kuptoj” = anlıyorum, “nuk kuptoj” = anlamıyorum. Bu kalıp seyahatte çok değerlidir çünkü bilmediğin her durumda nazikçe açıklama istemeni sağlar.`, practice: [`“Anlamıyorum” cümlesini Arnavutça söyle.`,`Birinden yavaş konuşmasını iste.`,`“Affedersiniz” ifadesini yol sorma öncesinde kullan.`,`“Sorun değil” cevabını ezberle.`,`Yardıma ihtiyacın olduğunu söyleyen bir cümle kur.`]},{day: 5, title: `Nerede ve Nasıl Soruları`, title_native: `Pyetje me ku dhe si`, focus: `Berat’ta müze, tuvalet, otel veya otobüs durağı ararken basit soru kelimeleriyle pratik yaparsın.`, vocab: [{sq: `ku`, tr: `nerede`, ipa: `ku`},{sq: `si`, tr: `nasıl`, ipa: `si`},{sq: `çfarë`, tr: `ne`, ipa: `ÇFA-rı`},{sq: `kur`, tr: `ne zaman`, ipa: `kur`},{sq: `pse`, tr: `neden`, ipa: `pse`},{sq: `këtu`, tr: `burada`, ipa: `kı-TU`},{sq: `atje`, tr: `orada`, ipa: `A-tye`},{sq: `afër`, tr: `yakın`, ipa: `A-fır`},{sq: `larg`, tr: `uzak`, ipa: `larg`},{sq: `rrugë`, tr: `yol / sokak`, ipa: `RRU-gı`}], phrases: [{sq: `Ku është hoteli?`, tr: `Otel nerede?`, ipa: `ku EŞ-tı ho-TE-li`},{sq: `Ku është tualeti?`, tr: `Tuvalet nerede?`, ipa: `ku EŞ-tı tu-a-LE-ti`},{sq: `A është afër?`, tr: `Yakın mı?`, ipa: `a EŞ-tı A-fır`},{sq: `Është larg?`, tr: `Uzak mı?`, ipa: `EŞ-tı larg`},{sq: `Si shkoj atje?`, tr: `Oraya nasıl giderim?`, ipa: `si ŞKOY A-tye`},{sq: `Çfarë është kjo?`, tr: `Bu nedir?`, ipa: `ÇFA-rı EŞ-tı kyo`}], grammar: `“Ku është ...?” yapısı “... nerede?” demektir. “Është” kelimesi “-dır / var / bulunuyor” gibi işlev görür. Pratikte sadece aradığın yeri sona ekleyerek hızlıca soru kurabilirsin.`, practice: [`“Otel nerede?” cümlesini Arnavutça kur.`,`“Yakın mı?” ve “Uzak mı?” sorularını karşılaştır.`,`Bir haritaya bakıp “Si shkoj atje?” de.`,`“Bu nedir?” sorusunu bir menü öğesi için kullan.`,`“Burada” ve “orada” kelimeleriyle iki kısa cümle kur.`]},{day: 6, title: `Yönler ve Yol Tarifi`, title_native: `Drejtimet dhe udhëzimet`, focus: `Gjirokastra’da taş sokaklarda yürürken sağ, sol, düz gitme ve köşe dönme ifadelerini öğrenirsin.`, vocab: [{sq: `djathtas`, tr: `sağa`, ipa: `DYATH-tas`},{sq: `majtas`, tr: `sola`, ipa: `MAY-tas`},{sq: `drejt`, tr: `düz`, ipa: `dreyt`},{sq: `përpara`, tr: `ileri`, ipa: `pır-PA-ra`},{sq: `mbrapa`, tr: `geri / arkada`, ipa: `MBRA-pa`},{sq: `ktheni`, tr: `dönün`, ipa: `KTHE-ni`},{sq: `shkoni`, tr: `gidin`, ipa: `ŞKO-ni`},{sq: `rrugica`, tr: `küçük sokak`, ipa: `rru-Gİ-tsa`},{sq: `kryqëzim`, tr: `kavşak`, ipa: `krü-çı-ZİM`},{sq: `hartë`, tr: `harita`, ipa: `HAR-tı`}], phrases: [{sq: `Shkoni drejt.`, tr: `Düz gidin.`, ipa: `ŞKO-ni dreyt`},{sq: `Ktheni djathtas.`, tr: `Sağa dönün.`, ipa: `KTHE-ni DYATH-tas`},{sq: `Ktheni majtas.`, tr: `Sola dönün.`, ipa: `KTHE-ni MAY-tas`},{sq: `Është përpara.`, tr: `İleride.`, ipa: `EŞ-tı pır-PA-ra`},{sq: `Është pas hotelit.`, tr: `Otelin arkasında.`, ipa: `EŞ-tı pas ho-TE-lit`},{sq: `A keni një hartë?`, tr: `Bir haritanız var mı?`, ipa: `a KE-ni nyı HAR-tı`}], grammar: `Emir veya yönlendirme verirken “shkoni” ve “ktheni” kibar biçimlerdir. Yol tarifi alırken bu kelimeleri duymaya çalış: “drejt”, “djathtas”, “majtas” genellikle en kritik bilgilerdir.`, practice: [`Sağ, sol ve düz kelimelerini sırayla söyle.`,`“Düz gidin, sonra sağa dönün” cümlesini iki parça hâlinde kur.`,`Birinden harita iste.`,`“İleride” ifadesini bir yer tarifi içinde kullan.`,`Telefon haritasında hayali bir rota tarif et.`]},{day: 7, title: `Kafede Sipariş`, title_native: `Porosia në kafene`, focus: `Tiran’daki bir kafede kahve, su ve küçük atıştırmalık sipariş etmeyi öğrenirsin. Arnavutluk’ta kahve kültürü güçlü olduğu için bu günlük pratik çok işe yarar.`, vocab: [{sq: `kafe`, tr: `kahve`, ipa: `KA-fe`},{sq: `ujë`, tr: `su`, ipa: `U-yı`},{sq: `çaj`, tr: `çay`, ipa: `çay`},{sq: `qumësht`, tr: `süt`, ipa: `çu-MIŞT`},{sq: `sheqer`, tr: `şeker`, ipa: `ŞE-çer`},{sq: `bukë`, tr: `ekmek`, ipa: `BU-kı`},{sq: `byrek`, tr: `börek`, ipa: `BÜ-rek`},{sq: `tavolinë`, tr: `masa`, ipa: `ta-vo-Lİ-nı`},{sq: `filxhan`, tr: `fincan`, ipa: `fil-DZAN`},{sq: `faturë`, tr: `hesap`, ipa: `fa-TU-rı`}], phrases: [{sq: `Një kafe, ju lutem.`, tr: `Bir kahve lütfen.`, ipa: `nyı KA-fe yu LU-tem`},{sq: `Një ujë pa gaz.`, tr: `Bir gazsız su.`, ipa: `nyı U-yı pa gaz`},{sq: `Me qumësht, ju lutem.`, tr: `Sütlü olsun lütfen.`, ipa: `me çu-MIŞT yu LU-tem`},{sq: `Pa sheqer, ju lutem.`, tr: `Şekersiz lütfen.`, ipa: `pa ŞE-çer yu LU-tem`},{sq: `A keni byrek?`, tr: `Börek var mı?`, ipa: `a KE-ni BÜ-rek`},{sq: `Faturën, ju lutem.`, tr: `Hesabı lütfen.`, ipa: `fa-TU-rın yu LU-tem`}], grammar: `“Me” “ile”, “pa” ise “-siz / olmadan” anlamına gelir. Kahve siparişinde “me qumësht” sütlü, “pa sheqer” şekersiz demektir. Bu iki kelime yemek ve içecek siparişlerinde çok kullanılır.`, practice: [`Şekersiz kahve siparişi ver.`,`Gazsız su istediğini söyle.`,`“Börek var mı?” sorusunu kullan.`,`Hesabı isteme cümlesini ezberle.`,`“Me” ve “pa” ile iki içecek tercihi oluştur.`]},{day: 8, title: `Restoranda Yemek Seçme`, title_native: `Zgjedhja e ushqimit në restorant`, focus: `Dıraç’ta sahil restoranında menü istemeyi, yemek seçmeyi ve temel malzemeleri sormayı öğrenirsin.`, vocab: [{sq: `restorant`, tr: `restoran`, ipa: `res-to-RANT`},{sq: `menu`, tr: `menü`, ipa: `me-NU`},{sq: `ushqim`, tr: `yemek`, ipa: `uş-ÇİM`},{sq: `mish`, tr: `et`, ipa: `miş`},{sq: `peshk`, tr: `balık`, ipa: `peşk`},{sq: `pulë`, tr: `tavuk`, ipa: `PU-lı`},{sq: `perime`, tr: `sebze`, ipa: `pe-Rİ-me`},{sq: `oriz`, tr: `pirinç`, ipa: `o-RİZ`},{sq: `kripë`, tr: `tuz`, ipa: `KRİ-pı`},{sq: `vaj ulliri`, tr: `zeytinyağı`, ipa: `vay ul-Lİ-ri`}], phrases: [{sq: `A mund të shoh menunë?`, tr: `Menüyü görebilir miyim?`, ipa: `a mund tı şoh me-NU-nı`},{sq: `Çfarë rekomandoni?`, tr: `Ne önerirsiniz?`, ipa: `ÇFA-rı re-ko-man-DO-ni`},{sq: `Dua peshk.`, tr: `Balık istiyorum.`, ipa: `DU-a peşk`},{sq: `Pa mish, ju lutem.`, tr: `Etsiz lütfen.`, ipa: `pa miş yu LU-tem`},{sq: `A ka perime?`, tr: `Sebze var mı?`, ipa: `a ka pe-Rİ-me`},{sq: `Ishte shumë e mirë.`, tr: `Çok güzeldi.`, ipa: `İŞ-te SHU-mı e Mİ-rı`}], grammar: `“Dua” “istiyorum” anlamına gelir ve çok pratik bir fiildir. “Dua peshk” balık istiyorum, “Dua ujë” su istiyorum demektir. Kibar olmak için sonuna “ju lutem” ekleyebilirsin.`, practice: [`Restoranda menü iste.`,`Garsona ne önerdiğini sor.`,`“Et istemiyorum” anlamında bir cümle kur.`,`“Sebze var mı?” sorusunu söyle.`,`Yemeğin güzel olduğunu ifade et.`]},{day: 9, title: `Kahvaltı ve Günlük Yiyecekler`, title_native: `Mëngjesi dhe ushqimet e përditshme`, focus: `Saranda’da otel kahvaltısında peynir, yumurta, ekmek ve içecekleri istemeyi öğrenirsin.`, vocab: [{sq: `mëngjes`, tr: `kahvaltı / sabah`, ipa: `MıN-gyes`},{sq: `vezë`, tr: `yumurta`, ipa: `VE-zı`},{sq: `djathë`, tr: `peynir`, ipa: `DYATH`},{sq: `gjalpë`, tr: `tereyağı`, ipa: `GYAL-pı`},{sq: `mjaltë`, tr: `bal`, ipa: `MYALT`},{sq: `kos`, tr: `yoğurt`, ipa: `kos`},{sq: `fruta`, tr: `meyveler`, ipa: `FRU-ta`},{sq: `lëng`, tr: `meyve suyu`, ipa: `lıng`},{sq: `domate`, tr: `domates`, ipa: `do-MA-te`},{sq: `kastravec`, tr: `salatalık`, ipa: `kas-tra-VETS`}], phrases: [{sq: `A ka mëngjes?`, tr: `Kahvaltı var mı?`, ipa: `a ka MıN-gyes`},{sq: `Dua vezë dhe djathë.`, tr: `Yumurta ve peynir istiyorum.`, ipa: `DU-a VE-zı dhe DYATH`},{sq: `A keni kos?`, tr: `Yoğurdunuz var mı?`, ipa: `a KE-ni kos`},{sq: `Një lëng portokalli, ju lutem.`, tr: `Bir portakal suyu lütfen.`, ipa: `nyı lıng por-to-KAL-li yu LU-tem`},{sq: `Pa gjalpë, ju lutem.`, tr: `Tereyağsız lütfen.`, ipa: `pa GYAL-pı yu LU-tem`},{sq: `Kjo është shumë e freskët.`, tr: `Bu çok taze.`, ipa: `kyo EŞ-tı SHU-mı e FRES-kıt`}], grammar: `“Dhe” “ve” anlamına gelir. Yiyecekleri birleştirirken çok kolay kullanılır: “vezë dhe djathë”, “bukë dhe mjaltë.” Arnavutçada bazı kelimelerin telaffuzu Türkçeye yakın değildir, bu yüzden “dj” sesini “dy” gibi okumaya çalış.`, practice: [`“Yumurta ve peynir istiyorum” cümlesini kur.`,`Kahvaltı olup olmadığını sor.`,`Bir portakal suyu sipariş et.`,`“Bu çok taze” ifadesini meyveler için kullan.`,`“Dhe” ile üç yiyecek birleştir.`]},{day: 10, title: `Alışveriş ve Fiyatlar`, title_native: `Blerjet dhe çmimet`, focus: `Kruja Çarşısı’nda hediyelik eşya bakarken fiyat sormayı, pahalı veya ucuz demeyi ve ödeme konuşmasını öğrenirsin.`, vocab: [{sq: `dyqan`, tr: `dükkân`, ipa: `dü-KAN`},{sq: `çmim`, tr: `fiyat`, ipa: `ÇMİM`},{sq: `para`, tr: `para`, ipa: `PA-ra`},{sq: `euro`, tr: `avro`, ipa: `EV-ro`},{sq: `lek`, tr: `Arnavut leki`, ipa: `lek`},{sq: `shtrenjtë`, tr: `pahalı`, ipa: `ŞTRENYT`},{sq: `lirë`, tr: `ucuz`, ipa: `Lİ-rı`},{sq: `dhuratë`, tr: `hediye`, ipa: `dhu-RA-tı`},{sq: `çantë`, tr: `çanta`, ipa: `ÇAN-tı`},{sq: `kartë`, tr: `kart`, ipa: `KAR-tı`}], phrases: [{sq: `Sa kushton kjo?`, tr: `Bu ne kadar?`, ipa: `sa KUŞ-ton kyo`},{sq: `Është shumë shtrenjtë.`, tr: `Çok pahalı.`, ipa: `EŞ-tı SHU-mı ŞTRENYT`},{sq: `A keni diçka më të lirë?`, tr: `Daha ucuz bir şeyiniz var mı?`, ipa: `a KE-ni DİÇ-ka mı tı Lİ-rı`},{sq: `Mund të paguaj me kartë?`, tr: `Kartla ödeyebilir miyim?`, ipa: `mund tı pa-GU-ay me KAR-tı`},{sq: `Do ta marr këtë.`, tr: `Bunu alacağım.`, ipa: `do ta marr Kı-tı`},{sq: `Është për dhuratë.`, tr: `Hediye için.`, ipa: `EŞ-tı pır dhu-RA-tı`}], grammar: `“Kjo” “bu” demektir ve genellikle yakınındaki bir şeyi gösterirken kullanılır. “Këtë” ise “bunu” anlamındadır: “Do ta marr këtë” = “Bunu alacağım.” Alışverişte bu kalıp çok kullanışlıdır.`, practice: [`Bir hediyelik eşyanın fiyatını sor.`,`Kartla ödeme yapıp yapamayacağını sor.`,`“Daha ucuz bir şey var mı?” cümlesini kullan.`,`“Bunu alacağım” ifadesini ezberle.`,`“Hediye için” diyerek paketleme istediğini canlandır.`]},{day: 11, title: `Renkler ve Giysiler`, title_native: `Ngjyrat dhe rrobat`, focus: `Prizren’de küçük bir butikte tişört, ceket veya ayakkabı bakarken renk, beden ve deneme ifadelerini öğrenirsin.`, vocab: [{sq: `ngjyrë`, tr: `renk`, ipa: `NGYÜ-rı`},{sq: `i bardhë`, tr: `beyaz`, ipa: `i BARDH`},{sq: `i zi`, tr: `siyah`, ipa: `i zi`},{sq: `i kuq`, tr: `kırmızı`, ipa: `i kuç`},{sq: `blu`, tr: `mavi`, ipa: `blu`},{sq: `jeshil`, tr: `yeşil`, ipa: `ye-ŞİL`},{sq: `rroba`, tr: `kıyafetler`, ipa: `RRO-ba`},{sq: `këpucë`, tr: `ayakkabı`, ipa: `kı-PU-tsı`},{sq: `madhësi`, tr: `beden / boyut`, ipa: `madh-ı-Sİ`},{sq: `provë`, tr: `deneme`, ipa: `PRO-vı`}], phrases: [{sq: `A keni këtë në blu?`, tr: `Bunun mavisi var mı?`, ipa: `a KE-ni Kı-tı nı blu`},{sq: `Çfarë madhësie është?`, tr: `Hangi beden?`, ipa: `ÇFA-rı madh-ı-Sİ-e EŞ-tı`},{sq: `Dua ta provoj.`, tr: `Denemek istiyorum.`, ipa: `DU-a ta pro-VOY`},{sq: `Është shumë e madhe.`, tr: `Çok büyük.`, ipa: `EŞ-tı SHU-mı e MA-dhe`},{sq: `Është shumë e vogël.`, tr: `Çok küçük.`, ipa: `EŞ-tı SHU-mı e VO-gıl`},{sq: `Më pëlqen kjo.`, tr: `Bunu beğendim.`, ipa: `mı PıL-çen kyo`}], grammar: `Sıfatlar Arnavutçada ismin cinsiyetine göre biçim değiştirebilir. Başlangıçta tüm sistemi ezberlemek yerine kalıpları kullan: “shumë e madhe” çok büyük, “shumë e vogël” çok küçük. Mağazada bu ifadeler anlaşılır.`, practice: [`Bir ürünün mavisini sor.`,`“Denemek istiyorum” cümlesini söyle.`,`Çok büyük ve çok küçük ifadelerini karşılaştır.`,`“Bunu beğendim” diyerek alışveriş diyaloğu oluştur.`,`Siyah, beyaz ve kırmızı renklerini tekrar et.`]},{day: 12, title: `Otobüs ve Toplu Taşıma`, title_native: `Autobusi dhe transporti publik`, focus: `Tiran’dan Berat’a ya da Priştine içinde bir yere giderken bilet alma, durak sorma ve kalkış saatini anlama pratiği yaparsın.`, vocab: [{sq: `autobus`, tr: `otobüs`, ipa: `au-to-BUS`},{sq: `biletë`, tr: `bilet`, ipa: `bi-LE-tı`},{sq: `stacion`, tr: `istasyon / durak`, ipa: `sta-TSİ-on`},{sq: `orë`, tr: `saat`, ipa: `O-rı`},{sq: `nisje`, tr: `kalkış`, ipa: `NİS-ye`},{sq: `mbërritje`, tr: `varış`, ipa: `mbı-RRİT-ye`},{sq: `qendër`, tr: `merkez`, ipa: `ÇEN-dır`},{sq: `linjë`, tr: `hat`, ipa: `Lİ-nyı`},{sq: `shofer`, tr: `şoför`, ipa: `ŞO-fer`},{sq: `vonesë`, tr: `gecikme`, ipa: `vo-NE-sı`}], phrases: [{sq: `Dua një biletë për Berat.`, tr: `Berat’a bir bilet istiyorum.`, ipa: `DU-a nyı bi-LE-tı pır be-RAT`},{sq: `Ku është stacioni?`, tr: `Durak nerede?`, ipa: `ku EŞ-tı sta-TSİ-o-ni`},{sq: `Në çfarë ore niset autobusi?`, tr: `Otobüs saat kaçta kalkıyor?`, ipa: `nı ÇFA-rı O-re Nİ-set au-to-BU-si`},{sq: `A shkon në qendër?`, tr: `Merkeze gider mi?`, ipa: `a ŞKON nı ÇEN-dır`},{sq: `Ka vonesë?`, tr: `Gecikme var mı?`, ipa: `ka vo-NE-sı`},{sq: `Dua të zbres këtu.`, tr: `Burada inmek istiyorum.`, ipa: `DU-a tı zbres kı-TU`}], grammar: `“Në” hem “-de / -da” hem de “-e / -a” anlamı verebilir. “Në qendër” merkeze veya merkezde anlamına bağlama göre değişir. Toplu taşımada yer adıyla birlikte sık duyarsın.`, practice: [`Berat’a bilet istediğini söyle.`,`Otobüsün kaçta kalktığını sor.`,`Merkeze gidip gitmediğini sor.`,`“Burada inmek istiyorum” ifadesini tekrar et.`,`“Gecikme var mı?” sorusunu canlandır.`]},{day: 13, title: `Taksi ve Araçla Ulaşım`, title_native: `Taksi dhe udhëtimi me makinë`, focus: `Havalimanından otele taksiyle giderken adres söylemeyi, yaklaşık fiyat sormayı ve kısa yönlendirme yapmayı öğrenirsin.`, vocab: [{sq: `taksi`, tr: `taksi`, ipa: `TAK-si`},{sq: `aeroport`, tr: `havalimanı`, ipa: `a-e-ro-PORT`},{sq: `adresë`, tr: `adres`, ipa: `a-DRE-sı`},{sq: `hotel`, tr: `otel`, ipa: `ho-TEL`},{sq: `çmim fiks`, tr: `sabit fiyat`, ipa: `ÇMİM fiks`},{sq: `metër`, tr: `taksimetre`, ipa: `ME-tır`},{sq: `këtu`, tr: `burada`, ipa: `kı-TU`},{sq: `ndaloni`, tr: `durun`, ipa: `nda-LO-ni`},{sq: `më shpejt`, tr: `daha hızlı`, ipa: `mı ŞPEYT`},{sq: `më ngadalë`, tr: `daha yavaş`, ipa: `mı nga-DA-lı`}], phrases: [{sq: `Dua të shkoj në këtë adresë.`, tr: `Bu adrese gitmek istiyorum.`, ipa: `DU-a tı ŞKOY nı Kı-tı a-DRE-sı`},{sq: `Sa kushton deri në hotel?`, tr: `Otele kadar ne kadar?`, ipa: `sa KUŞ-ton DE-ri nı ho-TEL`},{sq: `A përdorni metër?`, tr: `Taksimetre kullanıyor musunuz?`, ipa: `a pır-DO-ni ME-tır`},{sq: `Ju lutem, ndaloni këtu.`, tr: `Lütfen burada durun.`, ipa: `yu LU-tem nda-LO-ni kı-TU`},{sq: `Mund të shkoni më ngadalë?`, tr: `Daha yavaş gidebilir misiniz?`, ipa: `mund tı ŞKO-ni mı nga-DA-lı`},{sq: `Kjo është adresa.`, tr: `Adres bu.`, ipa: `kyo EŞ-tı a-DRE-sa`}], grammar: `“Dua të shkoj” “gitmek istiyorum” demektir. “Të” burada ikinci fiili bağlar. Seyahatte “Dua të...” kalıbıyla birçok ihtiyaç söyleyebilirsin: gitmek istiyorum, yemek istiyorum, ödemek istiyorum.`, practice: [`Taksiye bir adrese gitmek istediğini söyle.`,`Otele kadar fiyat sor.`,`Taksimetre kullanılıp kullanılmadığını sor.`,`“Burada durun” cümlesini ezberle.`,`Daha yavaş gitmesini kibarca iste.`]},{day: 14, title: `Otelde Giriş İşlemleri`, title_native: `Regjistrimi në hotel`, focus: `Tiran veya Saranda’da otele giriş yaparken rezervasyon, pasaport, oda ve anahtar kartı konuşmalarını öğrenirsin.`, vocab: [{sq: `rezervim`, tr: `rezervasyon`, ipa: `re-zer-VİM`},{sq: `pasaportë`, tr: `pasaport`, ipa: `pa-sa-POR-tı`},{sq: `dhomë`, tr: `oda`, ipa: `DHO-mı`},{sq: `çelës`, tr: `anahtar`, ipa: `çe-LIS`},{sq: `kartë dhome`, tr: `oda kartı`, ipa: `KAR-tı DHO-me`},{sq: `pritje`, tr: `resepsiyon`, ipa: `PRİT-ye`},{sq: `natë`, tr: `gece`, ipa: `NA-tı`},{sq: `bagazh`, tr: `bagaj`, ipa: `ba-GAZH`},{sq: `ashensor`, tr: `asansör`, ipa: `a-ŞEN-sor`},{sq: `mëngjes`, tr: `kahvaltı`, ipa: `MıN-gyes`}], phrases: [{sq: `Kam një rezervim.`, tr: `Bir rezervasyonum var.`, ipa: `kam nyı re-zer-VİM`},{sq: `Rezervimi është në emrin Cannon.`, tr: `Rezervasyon Cannon adına.`, ipa: `re-zer-Vİ-mi EŞ-tı nı EM-rin Cannon`},{sq: `Ja pasaporta ime.`, tr: `İşte pasaportum.`, ipa: `ya pa-sa-POR-ta İ-me`},{sq: `Ku është dhoma ime?`, tr: `Odam nerede?`, ipa: `ku EŞ-tı DHO-ma İ-me`},{sq: `A ka ashensor?`, tr: `Asansör var mı?`, ipa: `a ka a-ŞEN-sor`},{sq: `Në çfarë ore është mëngjesi?`, tr: `Kahvaltı saat kaçta?`, ipa: `nı ÇFA-rı O-re EŞ-tı MıN-gye-si`}], grammar: `“Kam” “sahibim / var” anlamına gelir. “Kam një rezervim” yani “Bir rezervasyonum var” otelde en önemli cümlelerden biridir. “Ime” “benim” anlamı katar: “dhoma ime” = odam.`, practice: [`Otele girişte rezervasyonun olduğunu söyle.`,`Pasaportunu verdiğini ifade et.`,`Odanın nerede olduğunu sor.`,`Kahvaltının saatini öğrenmek için soru kur.`,`Asansör olup olmadığını sor.`]},{day: 15, title: `Otelde Sorun Bildirme`, title_native: `Raportimi i problemeve në hotel`, focus: `Otel odasında klima, Wi-Fi, sıcak su veya temizlik sorunu olduğunda nazikçe yardım istemeyi öğrenirsin.`, vocab: [{sq: `problem`, tr: `sorun`, ipa: `prob-LEM`},{sq: `internet`, tr: `internet`, ipa: `in-ter-NET`},{sq: `Wi-Fi`, tr: `Wi-Fi`, ipa: `vay-fay`},{sq: `ujë i ngrohtë`, tr: `sıcak su`, ipa: `U-yı i NGROHT`},{sq: `klimë`, tr: `klima`, ipa: `KLİ-mı`},{sq: `dritë`, tr: `ışık`, ipa: `DRİT`},{sq: `pastër`, tr: `temiz`, ipa: `pas-TIR`},{sq: `pis`, tr: `kirli`, ipa: `pis`},{sq: `peshqir`, tr: `havlu`, ipa: `peş-ÇİR`},{sq: `ndërrim`, tr: `değişim`, ipa: `ndı-RRİM`}], phrases: [{sq: `Kam një problem.`, tr: `Bir sorunum var.`, ipa: `kam nyı prob-LEM`},{sq: `Wi-Fi nuk punon.`, tr: `Wi-Fi çalışmıyor.`, ipa: `vay-fay nuk PU-non`},{sq: `Nuk ka ujë të ngrohtë.`, tr: `Sıcak su yok.`, ipa: `nuk ka U-yı tı NGROHT`},{sq: `Klima nuk punon.`, tr: `Klima çalışmıyor.`, ipa: `KLİ-ma nuk PU-non`},{sq: `Dua një peshqir tjetër.`, tr: `Başka bir havlu istiyorum.`, ipa: `DU-a nyı peş-ÇİR TYE-tır`},{sq: `A mund të më ndihmoni?`, tr: `Bana yardım edebilir misiniz?`, ipa: `a mund tı mı ndiH-MO-ni`}], grammar: `“Nuk punon” “çalışmıyor” demektir. Cihaz, Wi-Fi, klima veya lamba için kullanabilirsin. “Tjetër” “başka / diğer” anlamındadır ve otelde ekstra eşya isterken işe yarar.`, practice: [`Wi-Fi’ın çalışmadığını söyle.`,`Sıcak su olmadığını belirt.`,`Başka bir havlu iste.`,`Yardım isteğini kibarca sor.`,`“Kam një problem” ile başlayan üç cümle kur.`]},{day: 16, title: `Zaman ve Saatler`, title_native: `Koha dhe orët`, focus: `Müzelerin açılış saatlerini, otobüs kalkışını ve buluşma zamanını anlamak için saat ifadelerini öğrenirsin.`, vocab: [{sq: `sot`, tr: `bugün`, ipa: `sot`},{sq: `nesër`, tr: `yarın`, ipa: `NE-sır`},{sq: `dje`, tr: `dün`, ipa: `dye`},{sq: `tani`, tr: `şimdi`, ipa: `TA-ni`},{sq: `më vonë`, tr: `daha sonra`, ipa: `mı VO-nı`},{sq: `orë`, tr: `saat`, ipa: `O-rı`},{sq: `minutë`, tr: `dakika`, ipa: `mi-NU-tı`},{sq: `hapur`, tr: `açık`, ipa: `HA-pur`},{sq: `mbyllur`, tr: `kapalı`, ipa: `MBÜL-lur`},{sq: `takim`, tr: `buluşma`, ipa: `ta-KİM`}], phrases: [{sq: `Sa është ora?`, tr: `Saat kaç?`, ipa: `sa EŞ-tı O-ra`},{sq: `Është ora tre.`, tr: `Saat üç.`, ipa: `EŞ-tı O-ra tre`},{sq: `Në çfarë ore hapet?`, tr: `Saat kaçta açılıyor?`, ipa: `nı ÇFA-rı O-re HA-pet`},{sq: `Në çfarë ore mbyllet?`, tr: `Saat kaçta kapanıyor?`, ipa: `nı ÇFA-rı O-re MBÜL-let`},{sq: `Shihemi më vonë.`, tr: `Sonra görüşürüz.`, ipa: `Şİ-he-mi mı VO-nı`},{sq: `Takimi është nesër.`, tr: `Buluşma yarın.`, ipa: `ta-Kİ-mi EŞ-tı NE-sır`}], grammar: `Saat sorarken “Sa është ora?” kullanılır. Açılma ve kapanma saatleri için “hapet” ve “mbyllet” kelimelerini tanımak yeterlidir. Turistik yerlerde tabelalarda “hapur” ve “mbyllur” görebilirsin.`, practice: [`Saatin kaç olduğunu sor.`,`Bir müzenin kaçta açıldığını sor.`,`“Buluşma yarın” cümlesini kur.`,`“Bugün, yarın, dün” kelimelerini tekrar et.`,`“Sonra görüşürüz” ifadesini vedalaşmada kullan.`]},{day: 17, title: `Günler ve Plan Yapma`, title_native: `Ditët dhe bërja e planeve`, focus: `Arnavutluk gezinde tur rezervasyonu, arkadaşla buluşma veya müze planı yaparken günleri ve basit plan cümlelerini öğrenirsin.`, vocab: [{sq: `e hënë`, tr: `pazartesi`, ipa: `e Hı-nı`},{sq: `e martë`, tr: `salı`, ipa: `e MAR-tı`},{sq: `e mërkurë`, tr: `çarşamba`, ipa: `e MıR-ku-rı`},{sq: `e enjte`, tr: `perşembe`, ipa: `e EN-tye`},{sq: `e premte`, tr: `cuma`, ipa: `e PREM-te`},{sq: `e shtunë`, tr: `cumartesi`, ipa: `e ŞTU-nı`},{sq: `e diel`, tr: `pazar`, ipa: `e Dİ-el`},{sq: `javë`, tr: `hafta`, ipa: `YA-vı`},{sq: `plan`, tr: `plan`, ipa: `plan`},{sq: `udhëtim`, tr: `gezi / yolculuk`, ipa: `udhı-TİM`}], phrases: [{sq: `Çfarë plani keni sot?`, tr: `Bugün ne planınız var?`, ipa: `ÇFA-rı PLA-ni KE-ni sot`},{sq: `Dua të bëj një tur nesër.`, tr: `Yarın bir tur yapmak istiyorum.`, ipa: `DU-a tı bıy nyı tur NE-sır`},{sq: `A është hapur të dielën?`, tr: `Pazar günü açık mı?`, ipa: `a EŞ-tı HA-pur tı Dİ-e-lın`},{sq: `Kam kohë të premten.`, tr: `Cuma günü vaktim var.`, ipa: `kam KO-hı tı PREM-ten`},{sq: `Nuk kam plan.`, tr: `Planım yok.`, ipa: `nuk kam plan`},{sq: `Shkojmë të shtunën.`, tr: `Cumartesi gidelim.`, ipa: `ŞKOY-mı tı ŞTU-nın`}], grammar: `Gün adları genellikle “e” ile başlar: “e hënë”, “e martë.” “Të premten” gibi biçimler “cuma günü” anlamına gelir. Seyahatte tam dilbilgisi yerine bu gün kalıplarını parça parça tanımak yeterlidir.`, practice: [`Haftanın günlerini sırayla söyle.`,`“Yarın bir tur yapmak istiyorum” cümlesini kur.`,`Bir yerin pazar günü açık olup olmadığını sor.`,`“Planım yok” ifadesini söyle.`,`Cumartesi gitmeyi öneren bir cümle kur.`]},{day: 18, title: `Hava Durumu ve Mevsimler`, title_native: `Moti dhe stinët`, focus: `Saranda sahilinde veya Prizren’de yürüyüş planlarken hava durumunu sormayı ve temel hava ifadelerini anlamayı öğrenirsin.`, vocab: [{sq: `mot`, tr: `hava durumu`, ipa: `mot`},{sq: `diell`, tr: `güneş`, ipa: `Dİ-el`},{sq: `shi`, tr: `yağmur`, ipa: `şi`},{sq: `borë`, tr: `kar`, ipa: `BO-rı`},{sq: `erë`, tr: `rüzgâr`, ipa: `E-rı`},{sq: `ngrohtë`, tr: `sıcak`, ipa: `NGROHT`},{sq: `ftohtë`, tr: `soğuk`, ipa: `FTOHT`},{sq: `re`, tr: `bulut`, ipa: `re`},{sq: `stinët`, tr: `mevsimler`, ipa: `STİ-nıt`},{sq: `pranverë`, tr: `ilkbahar`, ipa: `pran-VE-rı`}], phrases: [{sq: `Si është moti sot?`, tr: `Bugün hava nasıl?`, ipa: `si EŞ-tı MO-ti sot`},{sq: `Është ngrohtë.`, tr: `Hava sıcak.`, ipa: `EŞ-tı NGROHT`},{sq: `Është ftohtë.`, tr: `Hava soğuk.`, ipa: `EŞ-tı FTOHT`},{sq: `Po bie shi.`, tr: `Yağmur yağıyor.`, ipa: `po bi-e şi`},{sq: `A do të ketë diell?`, tr: `Güneş olacak mı?`, ipa: `a do tı KE-tı Dİ-el`},{sq: `Kam nevojë për çadër.`, tr: `Şemsiyeye ihtiyacım var.`, ipa: `kam ne-VO-yı pır ÇA-dır`}], grammar: `“Është” hava tariflerinde sık kullanılır: “Është ftohtë”, “Është ngrohtë.” “Po bie shi” kelime kelime “yağmur düşüyor” gibi düşünülebilir ve “yağmur yağıyor” demektir.`, practice: [`Bugünkü hava durumunu sor.`,`Havanın sıcak olduğunu söyle.`,`Yağmur yağdığını ifade et.`,`Şemsiyeye ihtiyacın olduğunu söyle.`,`“Güneş olacak mı?” sorusunu kullan.`]},{day: 19, title: `Telefon, İnternet ve Bağlantı`, title_native: `Telefoni, interneti dhe lidhja`, focus: `SIM kart almak, Wi-Fi şifresi sormak veya telefonunu şarj etmek için gereken ifadeleri öğrenirsin.`, vocab: [{sq: `telefon`, tr: `telefon`, ipa: `te-le-FON`},{sq: `kartë SIM`, tr: `SIM kart`, ipa: `KAR-tı sim`},{sq: `internet`, tr: `internet`, ipa: `in-ter-NET`},{sq: `fjalëkalim`, tr: `şifre`, ipa: `fya-lı-KA-lim`},{sq: `karikues`, tr: `şarj aleti`, ipa: `ka-ri-KU-es`},{sq: `bateri`, tr: `batarya`, ipa: `ba-te-Rİ`},{sq: `numër`, tr: `numara`, ipa: `NU-mır`},{sq: `mesazh`, tr: `mesaj`, ipa: `me-SAZH`},{sq: `thirrje`, tr: `arama`, ipa: `THİRR-ye`},{sq: `lidhje`, tr: `bağlantı`, ipa: `LİDH-ye`}], phrases: [{sq: `A keni Wi-Fi?`, tr: `Wi-Fi var mı?`, ipa: `a KE-ni vay-fay`},{sq: `Cili është fjalëkalimi?`, tr: `Şifre nedir?`, ipa: `TSİ-li EŞ-tı fya-lı-KA-li-mi`},{sq: `Dua një kartë SIM.`, tr: `Bir SIM kart istiyorum.`, ipa: `DU-a nyı KAR-tı sim`},{sq: `Telefoni im nuk ka bateri.`, tr: `Telefonumun şarjı yok.`, ipa: `te-le-FO-ni im nuk ka ba-te-Rİ`},{sq: `A mund ta karikoj këtu?`, tr: `Burada şarj edebilir miyim?`, ipa: `a mund ta ka-ri-KOY kı-TU`},{sq: `Numri im është ky.`, tr: `Numaram bu.`, ipa: `NU-mri im EŞ-tı kü`}], grammar: `“Im” “benim” anlamındadır ve erkek cinsiyetli isimlerde sık görülür: “telefoni im”, “numri im.” Şimdilik bunu kalıp olarak ezberlemek yeterli. “A mund...” ile başlayan sorular “... yapabilir miyim?” anlamındadır.`, practice: [`Wi-Fi şifresini sor.`,`SIM kart istediğini söyle.`,`Telefonunun şarjı olmadığını belirt.`,`Bir yerde telefonunu şarj edip edemeyeceğini sor.`,`Kendi numaranı gösterirken “Numri im është ky” de.`]},{day: 20, title: `Sağlık ve Eczane`, title_native: `Shëndeti dhe farmacia`, focus: `Eczaneye gidip baş ağrısı, mide rahatsızlığı veya alerji için yardım istemeyi öğrenirsin.`, vocab: [{sq: `farmaci`, tr: `eczane`, ipa: `far-ma-TSİ`},{sq: `ilaç`, tr: `ilaç`, ipa: `i-LAÇ`},{sq: `dhimbje`, tr: `ağrı`, ipa: `DHİMB-ye`},{sq: `kokë`, tr: `baş`, ipa: `KO-kı`},{sq: `stomak`, tr: `mide`, ipa: `sto-MAK`},{sq: `alergji`, tr: `alerji`, ipa: `a-ler-GYİ`},{sq: `temperaturë`, tr: `ateş`, ipa: `tem-pe-ra-TU-rı`},{sq: `mjek`, tr: `doktor`, ipa: `myek`},{sq: `spital`, tr: `hastane`, ipa: `spi-TAL`},{sq: `urgjencë`, tr: `acil`, ipa: `ur-GYEN-tsı`}], phrases: [{sq: `Ku është farmacia?`, tr: `Eczane nerede?`, ipa: `ku EŞ-tı far-ma-TSİ-a`},{sq: `Kam dhimbje koke.`, tr: `Başım ağrıyor.`, ipa: `kam DHİMB-ye KO-ke`},{sq: `Kam dhimbje stomaku.`, tr: `Midem ağrıyor.`, ipa: `kam DHİMB-ye sto-MA-ku`},{sq: `Kam alergji.`, tr: `Alerjim var.`, ipa: `kam a-ler-GYİ`},{sq: `A duhet të shkoj te mjeku?`, tr: `Doktora gitmeli miyim?`, ipa: `a DU-het tı ŞKOY te MYE-ku`},{sq: `Kam nevojë për ilaç.`, tr: `İlaca ihtiyacım var.`, ipa: `kam ne-VO-yı pır i-LAÇ`}], grammar: `“Kam dhimbje...” ağrım var demenin temel yoludur. “Koke” baş için, “stomaku” mide için kullanılır. Sağlık konularında kısa ve net cümleler kurmak en güvenli yaklaşımdır.`, practice: [`Eczanenin nerede olduğunu sor.`,`Başının ağrıdığını söyle.`,`Midende ağrı olduğunu ifade et.`,`Doktora gitmen gerekip gerekmediğini sor.`,`İlaca ihtiyacın olduğunu söyle.`]},{day: 21, title: `Acil Durumlar ve Güvenlik`, title_native: `Urgjencat dhe siguria`, focus: `Pasaport kaybı, cüzdan problemi veya acil yardım durumunda kısa ve net ifadeler kullanmayı öğrenirsin.`, vocab: [{sq: `ndihmë`, tr: `yardım`, ipa: `NDİH-mı`},{sq: `polici`, tr: `polis`, ipa: `po-li-TSİ`},{sq: `ambasadë`, tr: `elçilik`, ipa: `am-ba-SA-dı`},{sq: `pasaportë`, tr: `pasaport`, ipa: `pa-sa-POR-tı`},{sq: `portofol`, tr: `cüzdan`, ipa: `por-to-FOL`},{sq: `humbur`, tr: `kayıp`, ipa: `HUM-bur`},{sq: `vjedhur`, tr: `çalınmış`, ipa: `VYE-dhur`},{sq: `rrezik`, tr: `tehlike`, ipa: `RRE-zik`},{sq: `siguri`, tr: `güvenlik`, ipa: `si-gu-Rİ`},{sq: `telefonatë`, tr: `telefon araması`, ipa: `te-le-fo-NA-tı`}], phrases: [{sq: `Kam nevojë për ndihmë urgjente.`, tr: `Acil yardıma ihtiyacım var.`, ipa: `kam ne-VO-yı pır NDİH-mı ur-GYEN-te`},{sq: `Kam humbur pasaportën.`, tr: `Pasaportumu kaybettim.`, ipa: `kam HUM-bur pa-sa-POR-tın`},{sq: `Më kanë vjedhur portofolin.`, tr: `Cüzdanım çalındı.`, ipa: `mı KA-nı VYE-dhur por-to-FO-lin`},{sq: `Ku është policia?`, tr: `Polis nerede?`, ipa: `ku EŞ-tı po-li-TSİ-a`},{sq: `Dua të telefonoj ambasadën.`, tr: `Elçiliği aramak istiyorum.`, ipa: `DU-a tı te-le-fo-NOY am-ba-SA-dın`},{sq: `Nuk ndihem i sigurt.`, tr: `Kendimi güvende hissetmiyorum.`, ipa: `nuk NDİ-hem i si-GURT`}], grammar: `Acil durumlarda karmaşık cümle kurmaya gerek yoktur. “Kam humbur...” kaybettim, “më kanë vjedhur...” benden çaldılar anlamında kullanılır. Bu kalıpları ezberlemek pratik güvenlik sağlar.`, practice: [`Pasaportunu kaybettiğini söyle.`,`Cüzdanının çalındığını ifade et.`,`Polisi nerede bulacağını sor.`,`Elçiliği aramak istediğini söyle.`,`Kendini güvende hissetmediğini belirt.`]},{day: 22, title: `İnsanlarla Tanışma ve Sohbet`, title_native: `Njohja me njerëz dhe biseda`, focus: `Priştine’de bir kafede veya Tiran’da yürüyüş turunda yerel biriyle basit sohbet başlatmayı öğrenirsin.`, vocab: [{sq: `mik`, tr: `arkadaş`, ipa: `mik`},{sq: `mike`, tr: `kadın arkadaş`, ipa: `Mİ-ke`},{sq: `njerëz`, tr: `insanlar`, ipa: `NYE-rız`},{sq: `bisedë`, tr: `sohbet`, ipa: `bi-SE-dı`},{sq: `qytet`, tr: `şehir`, ipa: `çü-TET`},{sq: `vend`, tr: `yer / ülke`, ipa: `vend`},{sq: `familje`, tr: `aile`, ipa: `fa-MİL-ye`},{sq: `punë`, tr: `iş`, ipa: `PU-nı`},{sq: `pushime`, tr: `tatil`, ipa: `pu-Şİ-me`},{sq: `kënaqësi`, tr: `zevk / memnuniyet`, ipa: `kı-na-ÇI-si`}], phrases: [{sq: `Nga jeni?`, tr: `Nerelisiniz?`, ipa: `nga YE-ni`},{sq: `A jetoni këtu?`, tr: `Burada mı yaşıyorsunuz?`, ipa: `a ye-TO-ni kı-TU`},{sq: `Qyteti është shumë i bukur.`, tr: `Şehir çok güzel.`, ipa: `çü-TE-ti EŞ-tı SHU-mı i BU-kur`},{sq: `Jam këtu për pushime.`, tr: `Tatil için buradayım.`, ipa: `yam kı-TU pır pu-Şİ-me`},{sq: `Më pëlqen Shqipëria.`, tr: `Arnavutluk’u seviyorum.`, ipa: `mı PıL-çen Şçi-pı-Rİ-a`},{sq: `Ishte kënaqësi.`, tr: `Memnun oldum.`, ipa: `İŞ-te kı-na-ÇI-si`}], grammar: `“Më pëlqen...” “... hoşuma gidiyor / seviyorum” anlamındadır. Bir ülke, şehir veya yemek için kullanabilirsin. “Më pëlqen Tirana” veya “Më pëlqen byreku” gibi cümleler doğal duyulur.`, practice: [`Birine nereli olduğunu sor.`,`Burada yaşayıp yaşamadığını sor.`,`Şehrin güzel olduğunu söyle.`,`Tatil için orada olduğunu ifade et.`,`“Arnavutluk’u seviyorum” cümlesini söyle.`]},{day: 23, title: `Davetler ve Sosyal Planlar`, title_native: `Ftesat dhe planet shoqërore`, focus: `Yerel biriyle kahve içmek, yürüyüşe çıkmak veya akşam planı yapmak için nazik davet ifadeleri öğrenirsin.`, vocab: [{sq: `ftesë`, tr: `davet`, ipa: `FTE-sı`},{sq: `kafe`, tr: `kahve`, ipa: `KA-fe`},{sq: `darkë`, tr: `akşam yemeği`, ipa: `DAR-kı`},{sq: `drekë`, tr: `öğle yemeği`, ipa: `DRE-kı`},{sq: `shëtitje`, tr: `yürüyüş`, ipa: `şı-TİT-ye`},{sq: `sonte`, tr: `bu gece`, ipa: `SON-te`},{sq: `bashkë`, tr: `birlikte`, ipa: `BAŞ-kı`},{sq: `mund`, tr: `olabilir / yapabilir`, ipa: `mund`},{sq: `dakord`, tr: `tamam / anlaştık`, ipa: `da-KORD`},{sq: `ndoshta`, tr: `belki`, ipa: `NDOSH-ta`}], phrases: [{sq: `A do të pimë një kafe?`, tr: `Bir kahve içelim mi?`, ipa: `a do tı Pİ-mı nyı KA-fe`},{sq: `Dua të shëtis pak.`, tr: `Biraz yürümek istiyorum.`, ipa: `DU-a tı şı-TİS pak`},{sq: `A jeni i lirë sonte?`, tr: `Bu gece müsait misiniz?`, ipa: `a YE-ni i Lİ-rı SON-te`},{sq: `Mund të takohemi më vonë.`, tr: `Daha sonra buluşabiliriz.`, ipa: `mund tı ta-KO-he-mi mı VO-nı`},{sq: `Dakord, shihemi atje.`, tr: `Tamam, orada görüşürüz.`, ipa: `da-KORD Şİ-he-mi A-tye`},{sq: `Ndoshta nesër.`, tr: `Belki yarın.`, ipa: `NDOSH-ta NE-sır`}], grammar: `“A do të...?” geleceğe dönük öneri veya soru yapısında sık görülür. “A do të pimë një kafe?” günlük ve doğal bir davettir. Kibar reddetmek için “Ndoshta nesër” yumuşak bir seçenektir.`, practice: [`Bir kahve içmeyi teklif et.`,`Bu gece müsait olup olmadığını sor.`,`Daha sonra buluşabileceğinizi söyle.`,`“Belki yarın” ifadesini nazik cevap olarak kullan.`,`“Tamam, orada görüşürüz” cümlesini ezberle.`]},{day: 24, title: `Müze, Tur ve Gezilecek Yerler`, title_native: `Muzeu, turi dhe vendet për të vizituar`, focus: `Berat Kalesi, Gjirokastra Müzesi veya Tiran’daki Bunk’Art gibi yerleri gezerken bilet, tur ve fotoğraf izni sormayı öğrenirsin.`, vocab: [{sq: `muze`, tr: `müze`, ipa: `mu-ZE`},{sq: `kala`, tr: `kale`, ipa: `KA-la`},{sq: `tur`, tr: `tur`, ipa: `tur`},{sq: `udhërrëfyes`, tr: `rehber`, ipa: `udhı-RRı-fyes`},{sq: `biletë hyrjeje`, tr: `giriş bileti`, ipa: `bi-LE-tı HÜR-ye-ye`},{sq: `foto`, tr: `fotoğraf`, ipa: `FO-to`},{sq: `leje`, tr: `izin`, ipa: `LE-ye`},{sq: `histori`, tr: `tarih / hikâye`, ipa: `his-to-Rİ`},{sq: `ekspozitë`, tr: `sergi`, ipa: `eks-po-Zİ-tı`},{sq: `hyrje`, tr: `giriş`, ipa: `HÜR-ye`}], phrases: [{sq: `Dua një biletë hyrjeje.`, tr: `Bir giriş bileti istiyorum.`, ipa: `DU-a nyı bi-LE-tı HÜR-ye-ye`},{sq: `A ka tur me udhërrëfyes?`, tr: `Rehberli tur var mı?`, ipa: `a ka tur me udhı-RRı-fyes`},{sq: `Sa zgjat turi?`, tr: `Tur ne kadar sürüyor?`, ipa: `sa ZGYAT TU-ri`},{sq: `A lejohet foto?`, tr: `Fotoğraf çekmek serbest mi?`, ipa: `a le-YO-het FO-to`},{sq: `Ku është hyrja?`, tr: `Giriş nerede?`, ipa: `ku EŞ-tı HÜR-ya`},{sq: `Historia është interesante.`, tr: `Tarih ilginç.`, ipa: `his-to-Rİ-a EŞ-tı in-te-re-SAN-te`}], grammar: `“A lejohet...?” “... izinli mi / serbest mi?” anlamına gelir. Müze, kilise, cami veya resmi yerlerde fotoğraf çekmeden önce bu soruyu sormak naziktir. “Sa zgjat?” ise süre sormak için kullanılır.`, practice: [`Bir giriş bileti iste.`,`Rehberli tur olup olmadığını sor.`,`Turun ne kadar sürdüğünü sor.`,`Fotoğraf çekmenin serbest olup olmadığını sor.`,`“Tarih ilginç” cümlesini söyle.`]},{day: 25, title: `Plaj ve Doğa`, title_native: `Plazhi dhe natyra`, focus: `Saranda, Ksamil veya Ohri Gölü çevresinde plaj, güneşlenme, yüzme ve doğa gezisi ifadelerini öğrenirsin.`, vocab: [{sq: `plazh`, tr: `plaj`, ipa: `plazh`},{sq: `det`, tr: `deniz`, ipa: `det`},{sq: `liqen`, tr: `göl`, ipa: `li-ÇEN`},{sq: `mal`, tr: `dağ`, ipa: `mal`},{sq: `rërë`, tr: `kum`, ipa: `Rı-rı`},{sq: `diell`, tr: `güneş`, ipa: `Dİ-el`},{sq: `not`, tr: `yüzme`, ipa: `not`},{sq: `peshqir`, tr: `havlu`, ipa: `peş-ÇİR`},{sq: `çadër plazhi`, tr: `plaj şemsiyesi`, ipa: `ÇA-dır PLA-zhi`},{sq: `krem dielli`, tr: `güneş kremi`, ipa: `krem Dİ-el-li`}], phrases: [{sq: `Ku është plazhi më i afërt?`, tr: `En yakın plaj nerede?`, ipa: `ku EŞ-tı PLA-zhi mı i A-fırt`},{sq: `Dua të notoj.`, tr: `Yüzmek istiyorum.`, ipa: `DU-a tı no-TOY`},{sq: `A ka çadër plazhi?`, tr: `Plaj şemsiyesi var mı?`, ipa: `a ka ÇA-dır PLA-zhi`},{sq: `Kam nevojë për krem dielli.`, tr: `Güneş kremine ihtiyacım var.`, ipa: `kam ne-VO-yı pır krem Dİ-el-li`},{sq: `Deti është shumë i bukur.`, tr: `Deniz çok güzel.`, ipa: `DE-ti EŞ-tı SHU-mı i BU-kur`},{sq: `A është e sigurt për not?`, tr: `Yüzmek için güvenli mi?`, ipa: `a EŞ-tı e si-GURT pır not`}], grammar: `“Më i afërt” “en yakın” demektir ve yer sorularında çok yararlıdır. “Ku është ... më i afërt?” kalıbıyla eczane, plaj, durak veya market sorabilirsin.`, practice: [`En yakın plajı sor.`,`Yüzmek istediğini söyle.`,`Plaj şemsiyesi olup olmadığını sor.`,`Güneş kremine ihtiyacın olduğunu belirt.`,`Yüzmenin güvenli olup olmadığını sor.`]},{day: 26, title: `Ev, Mahalle ve Günlük Yaşam`, title_native: `Shtëpia, lagjja dhe jeta e përditshme`, focus: `Bir apartman dairesi, mahalle marketi veya konaklama çevresinde günlük yaşamla ilgili kelimeleri öğrenirsin.`, vocab: [{sq: `shtëpi`, tr: `ev`, ipa: `SHTı-pi`},{sq: `apartament`, tr: `apartman dairesi`, ipa: `a-par-ta-MENT`},{sq: `lagje`, tr: `mahalle`, ipa: `LAG-ye`},{sq: `market`, tr: `market`, ipa: `MAR-ket`},{sq: `furrë`, tr: `fırın`, ipa: `FUR-rı`},{sq: `derë`, tr: `kapı`, ipa: `DE-rı`},{sq: `dritare`, tr: `pencere`, ipa: `dri-TA-re`},{sq: `kuzhinë`, tr: `mutfak`, ipa: `ku-ZHİ-nı`},{sq: `banjë`, tr: `banyo`, ipa: `BAN-yı`},{sq: `çelës`, tr: `anahtar`, ipa: `çe-LIS`}], phrases: [{sq: `Ku është marketi më i afërt?`, tr: `En yakın market nerede?`, ipa: `ku EŞ-tı MAR-ke-ti mı i A-fırt`},{sq: `Kam humbur çelësin.`, tr: `Anahtarı kaybettim.`, ipa: `kam HUM-bur çe-LI-sin`},{sq: `Apartamenti është i pastër.`, tr: `Daire temiz.`, ipa: `a-par-ta-MEN-ti EŞ-tı i pas-TIR`},{sq: `A ka furrë afër?`, tr: `Yakında fırın var mı?`, ipa: `a ka FUR-rı A-fır`},{sq: `Dua ujë dhe bukë.`, tr: `Su ve ekmek istiyorum.`, ipa: `DU-a U-yı dhe BU-kı`},{sq: `Lagjja është e qetë.`, tr: `Mahalle sakin.`, ipa: `LAG-ya EŞ-tı e ÇE-tı`}], grammar: `“Afër” yakın, “më i afërt” en yakın anlamındadır. Günlük yaşamda “marketi më i afërt”, “farmacia më e afërt” gibi kalıplar kullanışlıdır. “Kam humbur...” kayıp eşya anlatırken yine işe yarar.`, practice: [`En yakın marketi sor.`,`Anahtarı kaybettiğini söyle.`,`Dairenin temiz olduğunu ifade et.`,`Yakında fırın olup olmadığını sor.`,`Su ve ekmek istediğini söyle.`]},{day: 27, title: `Duygular ve Tercihler`, title_native: `Ndjenjat dhe preferencat`, focus: `Seyahat sırasında neyi sevdiğini, neyi istemediğini ve nasıl hissettiğini anlatmayı öğrenirsin.`, vocab: [{sq: `i lumtur`, tr: `mutlu`, ipa: `i LUM-tur`},{sq: `i lodhur`, tr: `yorgun`, ipa: `i LODH-ur`},{sq: `i uritur`, tr: `aç`, ipa: `i u-Rİ-tur`},{sq: `i etur`, tr: `susamış`, ipa: `i E-tur`},{sq: `i shqetësuar`, tr: `endişeli`, ipa: `i şçe-Tı-su-ar`},{sq: `më pëlqen`, tr: `hoşuma gidiyor`, ipa: `mı PıL-çen`},{sq: `nuk më pëlqen`, tr: `hoşuma gitmiyor`, ipa: `nuk mı PıL-çen`},{sq: `dua`, tr: `istiyorum`, ipa: `DU-a`},{sq: `preferoj`, tr: `tercih ederim`, ipa: `pre-fe-ROY`},{sq: `më mirë`, tr: `daha iyi`, ipa: `mı Mİ-rı`}], phrases: [{sq: `Jam i lodhur.`, tr: `Yorgunum.`, ipa: `yam i LODH-ur`},{sq: `Jam i uritur.`, tr: `Açım.`, ipa: `yam i u-Rİ-tur`},{sq: `Kam etje.`, tr: `Susadım.`, ipa: `kam E-tye`},{sq: `Më pëlqen ky vend.`, tr: `Bu yeri beğendim.`, ipa: `mı PıL-çen kü vend`},{sq: `Nuk më pëlqen kjo.`, tr: `Bu hoşuma gitmedi.`, ipa: `nuk mı PıL-çen kyo`},{sq: `Preferoj diçka më të qetë.`, tr: `Daha sakin bir şeyi tercih ederim.`, ipa: `pre-fe-ROY DİÇ-ka mı tı ÇE-tı`}], grammar: `“Jam i...” erkek konuşan için birçok duygu veya durum anlatır. Kadın konuşan bazı sıfatlarda “e” kullanabilir, örneğin “Jam e lodhur.” Turist olarak anlaşılmak için temel kalıp yine de yeterince açıktır.`, practice: [`Yorgun olduğunu söyle.`,`Aç ve susamış olduğunu ifade et.`,`Bir yeri beğendiğini söyle.`,`Bir şeyin hoşuna gitmediğini nazikçe belirt.`,`Daha sakin bir yer tercih ettiğini söyle.`]},{day: 28, title: `Geçmiş Deneyimlerden Bahsetme`, title_native: `Të flasësh për përvoja të kaluara`, focus: `Bir turdan sonra ne gördüğünü, nerede yediğini veya gezinin nasıl geçtiğini basit geçmiş ifadelerle anlatırsın.`, vocab: [{sq: `pashë`, tr: `gördüm`, ipa: `PA-shı`},{sq: `shkova`, tr: `gittim`, ipa: `ŞKO-va`},{sq: `hëngra`, tr: `yedim`, ipa: `HıN-gra`},{sq: `piva`, tr: `içtim`, ipa: `Pİ-va`},{sq: `bleva`, tr: `satın aldım`, ipa: `BLE-va`},{sq: `vizitova`, tr: `ziyaret ettim`, ipa: `vi-zi-TO-va`},{sq: `dje`, tr: `dün`, ipa: `dye`},{sq: `sot`, tr: `bugün`, ipa: `sot`},{sq: `shumë`, tr: `çok`, ipa: `SHU-mı`},{sq: `bukuri`, tr: `güzellik`, ipa: `bu-ku-Rİ`}], phrases: [{sq: `Dje shkova në Berat.`, tr: `Dün Berat’a gittim.`, ipa: `dye ŞKO-va nı be-RAT`},{sq: `Pashë kalanë.`, tr: `Kaleyi gördüm.`, ipa: `PA-shı KA-la-nı`},{sq: `Hëngra ushqim shumë të mirë.`, tr: `Çok iyi yemek yedim.`, ipa: `HıN-gra uş-ÇİM SHU-mı tı Mİ-rı`},{sq: `Piva kafe në qendër.`, tr: `Merkezde kahve içtim.`, ipa: `Pİ-va KA-fe nı ÇEN-dır`},{sq: `Bleva një dhuratë.`, tr: `Bir hediye aldım.`, ipa: `BLE-va nyı dhu-RA-tı`},{sq: `Ishte një ditë e bukur.`, tr: `Güzel bir gündü.`, ipa: `İŞ-te nyı Dİ-tı e BU-kur`}], grammar: `Geçmiş zaman fiilleri başlangıçta ezberlenmiş kalıplar olarak öğrenilebilir: “shkova” gittim, “pashë” gördüm, “bleva” aldım. Seyahatte gününü anlatmak için bu birkaç fiil çok işe yarar.`, practice: [`Dün bir şehre gittiğini söyle.`,`Bir kale gördüğünü ifade et.`,`Merkezde kahve içtiğini söyle.`,`Bir hediye aldığını belirt.`,`“Güzel bir gündü” cümlesiyle günü bitir.`]},{day: 29, title: `Gelecek Planları ve Niyetler`, title_native: `Planet dhe synimet për të ardhmen`, focus: `Yarın nereye gideceğini, ne yapmak istediğini ve dönüş planını anlatmayı öğrenirsin.`, vocab: [{sq: `do të`, tr: `-ecek / -acak`, ipa: `do tı`},{sq: `nesër`, tr: `yarın`, ipa: `NE-sır`},{sq: `pasnesër`, tr: `yarından sonra`, ipa: `pas-NE-sır`},{sq: `planifikoj`, tr: `planlıyorum`, ipa: `pla-ni-fi-KOY`},{sq: `vizitoj`, tr: `ziyaret ediyorum`, ipa: `vi-zi-TOY`},{sq: `kthehem`, tr: `dönüyorum`, ipa: `KTHE-hem`},{sq: `nisem`, tr: `yola çıkıyorum`, ipa: `Nİ-sem`},{sq: `mëngjes`, tr: `sabah`, ipa: `MıN-gyes`},{sq: `mbrëmje`, tr: `akşam`, ipa: `MBRıM-ye`},{sq: `udhëtim`, tr: `yolculuk`, ipa: `udhı-TİM`}], phrases: [{sq: `Nesër do të shkoj në Gjirokastër.`, tr: `Yarın Gjirokastra’ya gideceğim.`, ipa: `NE-sır do tı ŞKOY nı gyiro-KAS-tır`},{sq: `Do të vizitoj muzeun.`, tr: `Müzeyi ziyaret edeceğim.`, ipa: `do tı vi-zi-TOY mu-ZE-un`},{sq: `Do të nisem në mëngjes.`, tr: `Sabah yola çıkacağım.`, ipa: `do tı Nİ-sem nı MıN-gyes`},{sq: `Do të kthehem në mbrëmje.`, tr: `Akşam döneceğim.`, ipa: `do tı KTHE-hem nı MBRıM-ye`},{sq: `Kam plan të shkoj në plazh.`, tr: `Plaja gitme planım var.`, ipa: `kam plan tı ŞKOY nı plazh`},{sq: `Udhëtimi do të jetë i gjatë.`, tr: `Yolculuk uzun olacak.`, ipa: `udhı-Tİ-mi do tı YE-tı i GYA-tı`}], grammar: `“Do të” gelecek zaman kurmak için çok kullanılır. “Do të shkoj” gideceğim, “do të vizitoj” ziyaret edeceğim demektir. Plan anlatırken bu yapı net ve anlaşılırdır.`, practice: [`Yarın bir şehre gideceğini söyle.`,`Bir müzeyi ziyaret edeceğini ifade et.`,`Sabah yola çıkacağını söyle.`,`Akşam döneceğini belirt.`,`Yolculuğun uzun olacağını anlat.`]},{day: 30, title: `Seyahat Sonu ve Genel Tekrar`, title_native: `Fundi i udhëtimit dhe përsëritja`, focus: `Dönüş günü otelden ayrılma, teşekkür etme, son alışveriş ve vedalaşma ifadelerini tekrar edersin.`, vocab: [{sq: `fund`, tr: `son`, ipa: `fund`},{sq: `udhëtim`, tr: `yolculuk`, ipa: `udhı-TİM`},{sq: `valixhe`, tr: `bavul`, ipa: `va-Lİ-dzhe`},{sq: `check-out`, tr: `çıkış işlemi`, ipa: `çek-aut`},{sq: `fluturim`, tr: `uçuş`, ipa: `flu-tu-RİM`},{sq: `aeroport`, tr: `havalimanı`, ipa: `a-e-ro-PORT`},{sq: `kujtime`, tr: `anılar`, ipa: `kuy-Tİ-me`},{sq: `faleminderit`, tr: `teşekkür ederim`, ipa: `fa-le-min-DE-rit`},{sq: `shpresoj`, tr: `umarım`, ipa: `shpre-SOY`},{sq: `kthehem`, tr: `dönmek`, ipa: `KTHE-hem`}], phrases: [{sq: `Dua të bëj check-out.`, tr: `Çıkış yapmak istiyorum.`, ipa: `DU-a tı bıy çek-aut`},{sq: `A mund ta lini valixhen këtu?`, tr: `Bavulu burada bırakabilir miyim?`, ipa: `a mund ta Lİ-ni va-Lİ-dzhen kı-TU`},{sq: `Fluturimi im është sot.`, tr: `Uçuşum bugün.`, ipa: `flu-tu-Rİ-mi im EŞ-tı sot`},{sq: `Faleminderit për gjithçka.`, tr: `Her şey için teşekkür ederim.`, ipa: `fa-le-min-DE-rit pır GYİTH-çka`},{sq: `Ishte një udhëtim shumë i bukur.`, tr: `Çok güzel bir yolculuktu.`, ipa: `İŞ-te nyı udhı-TİM SHU-mı i BU-kur`},{sq: `Shpresoj të kthehem përsëri.`, tr: `Umarım tekrar dönerim.`, ipa: `shpre-SOY tı KTHE-hem pır-Sı-ri`}], grammar: `“Për” “için” anlamındadır: “për gjithçka” her şey için, “për pushime” tatil için. Seyahat sonunda teşekkür etmek için “Faleminderit për gjithçka” çok doğal ve sıcak bir ifadedir.`, practice: [`Otelden çıkış yapmak istediğini söyle.`,`Bavulunu burada bırakıp bırakamayacağını sor.`,`Uçuşunun bugün olduğunu ifade et.`,`Her şey için teşekkür et.`,`Tekrar dönmeyi umduğunu söyle.`]}];

var CONVERSATIONS_TR_SQ = [{id: 1, title: `Kafede Kahve Siparişi`, scene: `Tiran’da küçük ve kalabalık bir kafedesin. Tezgâha yaklaşıp kahve ve su sipariş ediyorsun, sonra hesabı istiyorsun.`, lines: [{who: `them`, sq: `Mirëdita, çfarë dëshironi?`, tr: `İyi günler, ne istersiniz?`},{who: `you`, sq: `Mirëdita, një kafe, ju lutem.`, tr: `İyi günler, bir kahve lütfen.`},{who: `them`, sq: `Me sheqer apo pa sheqer?`, tr: `Şekerli mi şekersiz mi?`},{who: `you`, sq: `Pa sheqer, ju lutem.`, tr: `Şekersiz lütfen.`},{who: `them`, sq: `Dëshironi edhe ujë?`, tr: `Su da ister misiniz?`},{who: `you`, sq: `Po, një ujë pa gaz.`, tr: `Evet, bir gazsız su.`},{who: `them`, sq: `Urdhëroni, kafeja dhe uji.`, tr: `Buyurun, kahve ve su.`},{who: `you`, sq: `Faleminderit, sa kushton?`, tr: `Teşekkür ederim, ne kadar?`},{who: `them`, sq: `Kushton tre euro.`, tr: `Üç avro tutuyor.`},{who: `you`, sq: `Mund të paguaj me kartë?`, tr: `Kartla ödeyebilir miyim?`},{who: `them`, sq: `Po, sigurisht.`, tr: `Evet, tabii.`},{who: `you`, sq: `Faleminderit, mirupafshim.`, tr: `Teşekkür ederim, hoşça kalın.`}]},{id: 2, title: `Otelde Giriş`, scene: `Saranda’da denize yakın bir otele giriş yapıyorsun. Resepsiyon görevlisine rezervasyonunu söylüyor, pasaportunu veriyor ve kahvaltı saatini soruyorsun.`, lines: [{who: `them`, sq: `Mirëmbrëma, mirë se erdhët.`, tr: `İyi akşamlar, hoş geldiniz.`},{who: `you`, sq: `Mirëmbrëma, kam një rezervim.`, tr: `İyi akşamlar, bir rezervasyonum var.`},{who: `them`, sq: `Në cilin emër është rezervimi?`, tr: `Rezervasyon hangi isim adına?`},{who: `you`, sq: `Rezervimi është në emrin Cannon.`, tr: `Rezervasyon Cannon adına.`},{who: `them`, sq: `A mund të shoh pasaportën?`, tr: `Pasaportu görebilir miyim?`},{who: `you`, sq: `Po, ja pasaporta ime.`, tr: `Evet, işte pasaportum.`},{who: `them`, sq: `Dhoma juaj është në katin e dytë.`, tr: `Odanız ikinci katta.`},{who: `you`, sq: `Faleminderit, a ka ashensor?`, tr: `Teşekkür ederim, asansör var mı?`},{who: `them`, sq: `Po, ashensori është majtas.`, tr: `Evet, asansör solda.`},{who: `you`, sq: `Në çfarë ore është mëngjesi?`, tr: `Kahvaltı saat kaçta?`},{who: `them`, sq: `Mëngjesi është nga ora shtatë deri në dhjetë.`, tr: `Kahvaltı saat yediden ona kadar.`},{who: `you`, sq: `Shumë mirë, faleminderit.`, tr: `Çok iyi, teşekkür ederim.`}]},{id: 3, title: `Yol Tarifi Sorma`, scene: `Berat’ta eski şehirde kaleye yürümek istiyorsun. Bir yerliye yaklaşıp yön soruyorsun ve yolu tekrar ettiriyorsun.`, lines: [{who: `you`, sq: `Më falni, ku është kalaja?`, tr: `Affedersiniz, kale nerede?`},{who: `them`, sq: `Kalaja është lart, jo shumë larg.`, tr: `Kale yukarıda, çok uzak değil.`},{who: `you`, sq: `Si shkoj atje?`, tr: `Oraya nasıl giderim?`},{who: `them`, sq: `Shkoni drejt dhe pastaj ktheni majtas.`, tr: `Düz gidin ve sonra sola dönün.`},{who: `you`, sq: `Pas sa minutash?`, tr: `Kaç dakika sonra?`},{who: `them`, sq: `Rreth dhjetë minuta në këmbë.`, tr: `Yürüyerek yaklaşık on dakika.`},{who: `you`, sq: `A mund ta përsërisni ngadalë?`, tr: `Yavaşça tekrar edebilir misiniz?`},{who: `them`, sq: `Po, drejt, pastaj majtas te rrugica.`, tr: `Evet, düz, sonra küçük sokakta sola.`},{who: `you`, sq: `Është afër muzeut?`, tr: `Müzenin yakınında mı?`},{who: `them`, sq: `Po, është afër muzeut.`, tr: `Evet, müzenin yakınında.`},{who: `you`, sq: `Faleminderit shumë.`, tr: `Çok teşekkür ederim.`},{who: `them`, sq: `S’ka problem, udhëtim të mbarë.`, tr: `Sorun değil, iyi yolculuklar.`}]},{id: 4, title: `Restoranda Akşam Yemeği`, scene: `Dıraç sahilinde bir restorandasın. Menü istiyor, balık önerisi alıyor ve yemeğin sonunda hesabı istiyorsun.`, lines: [{who: `them`, sq: `Mirëmbrëma, a keni rezervim?`, tr: `İyi akşamlar, rezervasyonunuz var mı?`},{who: `you`, sq: `Jo, nuk kam rezervim.`, tr: `Hayır, rezervasyonum yok.`},{who: `them`, sq: `S’ka problem, kjo tavolinë është e lirë.`, tr: `Sorun değil, bu masa boş.`},{who: `you`, sq: `A mund të shoh menunë?`, tr: `Menüyü görebilir miyim?`},{who: `them`, sq: `Po, urdhëroni.`, tr: `Evet, buyurun.`},{who: `you`, sq: `Çfarë rekomandoni?`, tr: `Ne önerirsiniz?`},{who: `them`, sq: `Rekomandoj peshkun e freskët.`, tr: `Taze balığı öneririm.`},{who: `you`, sq: `Mirë, dua peshk dhe perime.`, tr: `Tamam, balık ve sebze istiyorum.`},{who: `them`, sq: `Dëshironi edhe verë apo ujë?`, tr: `Şarap veya su da ister misiniz?`},{who: `you`, sq: `Vetëm ujë, ju lutem.`, tr: `Sadece su lütfen.`},{who: `them`, sq: `Si ishte ushqimi?`, tr: `Yemek nasıldı?`},{who: `you`, sq: `Ishte shumë i mirë, faturën ju lutem.`, tr: `Çok iyiydi, hesabı lütfen.`}]},{id: 5, title: `Otobüs Bileti Alma`, scene: `Tiran otobüs terminalindesin ve Berat’a gitmek istiyorsun. Kalkış saatini, fiyatı ve doğru peronu soruyorsun.`, lines: [{who: `them`, sq: `Përshëndetje, ku doni të shkoni?`, tr: `Merhaba, nereye gitmek istiyorsunuz?`},{who: `you`, sq: `Dua një biletë për Berat.`, tr: `Berat’a bir bilet istiyorum.`},{who: `them`, sq: `Për sot apo për nesër?`, tr: `Bugün için mi yarın için mi?`},{who: `you`, sq: `Për sot, ju lutem.`, tr: `Bugün için lütfen.`},{who: `them`, sq: `Autobusi niset në orën njëmbëdhjetë.`, tr: `Otobüs saat on birde kalkıyor.`},{who: `you`, sq: `Sa kushton bileta?`, tr: `Bilet ne kadar?`},{who: `them`, sq: `Kushton tetë euro.`, tr: `Sekiz avro tutuyor.`},{who: `you`, sq: `A mund të paguaj me kartë?`, tr: `Kartla ödeyebilir miyim?`},{who: `them`, sq: `Jo, vetëm para.`, tr: `Hayır, sadece nakit.`},{who: `you`, sq: `Mirë, ja paratë.`, tr: `Tamam, işte para.`},{who: `them`, sq: `Autobusi është te platforma dy.`, tr: `Otobüs ikinci peronda.`},{who: `you`, sq: `Faleminderit, mirupafshim.`, tr: `Teşekkür ederim, hoşça kalın.`}]},{id: 6, title: `Çarşıda Alışveriş`, scene: `Kruja Çarşısı’nda küçük bir hediyelik eşya dükkânındasın. Bir çanta beğeniyor, fiyat soruyor ve daha ucuz seçenek arıyorsun.`, lines: [{who: `them`, sq: `Mirëdita, a mund t’ju ndihmoj?`, tr: `İyi günler, size yardım edebilir miyim?`},{who: `you`, sq: `Po, sa kushton kjo çantë?`, tr: `Evet, bu çanta ne kadar?`},{who: `them`, sq: `Kushton njëzet euro.`, tr: `Yirmi avro tutuyor.`},{who: `you`, sq: `Është pak shtrenjtë.`, tr: `Biraz pahalı.`},{who: `them`, sq: `Kam edhe diçka më të lirë.`, tr: `Daha ucuz bir şeyim de var.`},{who: `you`, sq: `A mund ta shoh?`, tr: `Görebilir miyim?`},{who: `them`, sq: `Po, kjo kushton dymbëdhjetë euro.`, tr: `Evet, bu on iki avro.`},{who: `you`, sq: `Më pëlqen kjo.`, tr: `Bunu beğendim.`},{who: `them`, sq: `Është për ju apo për dhuratë?`, tr: `Sizin için mi yoksa hediye mi?`},{who: `you`, sq: `Është për dhuratë.`, tr: `Hediye için.`},{who: `them`, sq: `Do ta paketoj bukur.`, tr: `Güzelce paketleyeceğim.`},{who: `you`, sq: `Faleminderit, do ta marr këtë.`, tr: `Teşekkür ederim, bunu alacağım.`}]},{id: 7, title: `Eczanede Yardım İsteme`, scene: `Prizren’de yürürken başın ağrıyor ve en yakın eczaneye giriyorsun. Eczacıya durumunu anlatıp uygun bir ilaç istiyorsun.`, lines: [{who: `them`, sq: `Përshëndetje, si mund t’ju ndihmoj?`, tr: `Merhaba, size nasıl yardımcı olabilirim?`},{who: `you`, sq: `Përshëndetje, kam dhimbje koke.`, tr: `Merhaba, başım ağrıyor.`},{who: `them`, sq: `A keni temperaturë?`, tr: `Ateşiniz var mı?`},{who: `you`, sq: `Jo, nuk kam temperaturë.`, tr: `Hayır, ateşim yok.`},{who: `them`, sq: `A keni alergji ndaj ndonjë ilaçi?`, tr: `Herhangi bir ilaca alerjiniz var mı?`},{who: `you`, sq: `Jo, nuk kam alergji.`, tr: `Hayır, alerjim yok.`},{who: `them`, sq: `Ky ilaç është për dhimbje koke.`, tr: `Bu ilaç baş ağrısı içindir.`},{who: `you`, sq: `Si duhet ta marr?`, tr: `Nasıl almalıyım?`},{who: `them`, sq: `Merreni me ujë pas ushqimit.`, tr: `Yemekten sonra suyla alın.`},{who: `you`, sq: `Faleminderit, sa kushton?`, tr: `Teşekkür ederim, ne kadar?`},{who: `them`, sq: `Kushton pesë euro.`, tr: `Beş avro tutuyor.`},{who: `you`, sq: `Mirë, faleminderit për ndihmën.`, tr: `Tamam, yardımınız için teşekkür ederim.`}]},{id: 8, title: `Yerel Biriyle Küçük Sohbet`, scene: `Tiran’da bir parkta oturuyorsun ve yanında oturan yerel biri sohbet başlatıyor. Şehir, tatil ve kahve hakkında doğal bir konuşma yapıyorsun.`, lines: [{who: `you`, sq: `Përshëndetje, a është i lirë ky vend?`, tr: `Merhaba, bu yer boş mu?`},{who: `them`, sq: `Po, sigurisht, uluni.`, tr: `Evet, tabii, oturun.`},{who: `you`, sq: `Faleminderit, qyteti është shumë i bukur.`, tr: `Teşekkür ederim, şehir çok güzel.`},{who: `them`, sq: `A jeni këtu për pushime?`, tr: `Tatil için mi buradasınız?`},{who: `you`, sq: `Po, jam nga Turqia.`, tr: `Evet, Türkiye’denim.`},{who: `them`, sq: `Mirë se erdhët në Tiranë.`, tr: `Tiran’a hoş geldiniz.`},{who: `you`, sq: `Faleminderit, më pëlqen shumë këtu.`, tr: `Teşekkür ederim, burayı çok seviyorum.`},{who: `them`, sq: `A keni provuar byrekun?`, tr: `Böreği denediniz mi?`},{who: `you`, sq: `Po, hëngra byrek sot në mëngjes.`, tr: `Evet, bugün sabah börek yedim.`},{who: `them`, sq: `Shumë mirë, dhe kafeja këtu është e mirë.`, tr: `Çok iyi, burada kahve de güzeldir.`},{who: `you`, sq: `Atëherë do të pi një kafe më vonë.`, tr: `O zaman daha sonra bir kahve içeceğim.`},{who: `them`, sq: `Kënaqësi, shijoni udhëtimin.`, tr: `Memnun oldum, yolculuğun tadını çıkarın.`}]}];